import React, { useState, useEffect } from 'react';
import { ShoppingCart, Package } from 'lucide-react';
import { validateCartAddition } from '../utils/cartHelpers';
import Carrito from './Carrito';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [cart, setCart] = useState([]);

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];
    
    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      const ofertasMapeadas = ofertasLocal.map(o => ({
        ...o,
        keyUnica: `local-${local.id}-prod-${o.id}`,
        localId: local.id,
        nombreLocal: local.nombre
      }));
      acumulador = [...acumulador, ...ofertasMapeadas];
    });
    setTodasLasOfertas(acumulador);
  }, []);

  const agregarAlCarrito = (producto) => {
    const checkLogistica = validateCartAddition(cart, producto, 'delivery');
    if (!checkLogistica.valid) return alert(checkLogistica.msg);

    // VALIDACIÓN DE STOCK
    const unidadesEnCarrito = cart.filter(item => item.id === producto.id).length;
    if (unidadesEnCarrito >= producto.stock) {
      return alert(`¡Lo sentimos! Solo quedan ${producto.stock} unidades de este producto.`);
    }

    setCart([...cart, { ...producto, instanceId: Date.now() + Math.random() }]);
  };

  return (
    <div style={{ display: 'flex', gap: '30px', padding: '40px 5%', background: '#f8fafc', minHeight: '100vh' }}>
      <div style={{ flex: 1 }}>
        <h2 style={{ marginBottom: '25px', color: '#1e293b' }}>Ofertas del Día</h2>
        <div style={grid}>
          {todasLasOfertas.map(o => (
            <div key={o.keyUnica} style={card}>
              {/* Imagen del Producto */}
              <div style={imageWrapper}>
                {o.imagen ? (
                  <img src={o.imagen} alt={o.producto} style={imgStyle} />
                ) : (
                  <div style={noImg}><Package size={40} color="#cbd5e1" /></div>
                )}
                <div style={localBadge}>{o.nombreLocal}</div>
              </div>

              <div style={cardBody}>
                <h3 style={titleStyle}>{o.producto}</h3>
                
                <div style={infoRow}>
                  <span style={pesoTag}>{o.peso.toFixed(3)} kg</span>
                  <span style={{...stockTag, color: o.stock < 5 ? '#ef4444' : '#10b981'}}>
                    {o.stock > 0 ? `${o.stock} disp.` : 'Sin Stock'}
                  </span>
                </div>

                <div style={priceRow}>
                  <div>
                    <span style={oldPrice}>${o.precioViejo}</span>
                    <span style={price}>${o.precioNuevo}</span>
                  </div>
                  <button 
                    onClick={() => agregarAlCarrito(o)} 
                    disabled={o.stock <= 0}
                    style={o.stock <= 0 ? btnDisabled : btnAdd}
                  >
                    <ShoppingCart size={18} />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
      {cart.length > 0 && <Carrito cart={cart} setCart={setCart} onCheckout={() => {alert("¡Pago Exitoso!"); setCart([])}} />}
    </div>
  );
};

// --- ESTILOS ACTUALIZADOS ---
const grid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '25px' };
const card = { background: 'white', borderRadius: '20px', overflow: 'hidden', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', transition: '0.3s' };
const imageWrapper = { position: 'relative', height: '180px', background: '#f1f5f9' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const noImg = { width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const localBadge = { position: 'absolute', top: '10px', left: '10px', background: 'rgba(30, 41, 59, 0.8)', color: 'white', padding: '4px 10px', borderRadius: '20px', fontSize: '0.7rem', fontWeight: 'bold', backdropFilter: 'blur(4px)' };
const cardBody = { padding: '15px' };
const titleStyle = { margin: '0 0 10px 0', fontSize: '1.1rem', color: '#1e293b' };
const infoRow = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };
const pesoTag = { fontSize: '0.8rem', color: '#94a3b8' };
const stockTag = { fontSize: '0.8rem', fontWeight: 'bold' };
const priceRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: '1px solid #f1f5f9', paddingTop: '12px' };
const oldPrice = { textDecoration: 'line-through', color: '#94a3b8', fontSize: '0.85rem', marginRight: '8px' };
const price = { fontSize: '1.3rem', fontWeight: 'bold', color: '#e67e22' };
const btnAdd = { background: '#1e293b', color: 'white', border: 'none', padding: '10px 15px', borderRadius: '12px', cursor: 'pointer' };
const btnDisabled = { ...btnAdd, background: '#cbd5e1', cursor: 'not-allowed' };

export default PanelCliente;
